import torch

try:
    import triton
    import triton.language as tl
    _HAS_TRITON = True
except Exception:
    _HAS_TRITON = False


if _HAS_TRITON:
    @triton.jit
    def _scale_inplace_kernel(real_ptr, n_float, inv_scale, BLOCK: tl.constexpr):
        pid = tl.program_id(0)
        offs = pid * BLOCK + tl.arange(0, BLOCK)
        mask = offs < n_float
        v = tl.load(real_ptr + offs, mask=mask, other=0.0)
        tl.store(real_ptr + offs, v * inv_scale, mask=mask)


_BLOCK = 1024
_cache = {}
_triton_checked = False
_triton_ok = _HAS_TRITON


def _torch_ref(x):
    seqlen = x.shape[2]
    fft_size = 2 * seqlen
    xf = torch.fft.rfft(x.to(torch.float32), n=fft_size)
    xf = xf / fft_size
    return xf.real.contiguous(), xf.imag.contiguous()


def _check_triton(device):
    global _triton_checked, _triton_ok
    if _triton_checked:
        return
    _triton_checked = True
    if not _HAS_TRITON:
        _triton_ok = False
        return

    try:
        t = torch.randn(2, 3, 5, device=device, dtype=torch.float32)
        ref = torch.fft.rfft(t, n=10)
        xf = ref.clone()
        xr = torch.view_as_real(xf)
        n_float = xr.numel()
        grid = ((n_float + _BLOCK - 1) // _BLOCK,)
        _scale_inplace_kernel[grid](xr, n_float, 0.1, BLOCK=_BLOCK)
        if not torch.allclose(xf, ref / 10.0, atol=1e-5, rtol=1e-5):
            _triton_ok = False
    except Exception:
        _triton_ok = False


def _scale_inplace(xf, scale):
    inv_scale = 1.0 / float(scale)
    if _triton_ok:
        xr = torch.view_as_real(xf)
        n_float = xr.numel()
        grid = ((n_float + _BLOCK - 1) // _BLOCK,)
        _scale_inplace_kernel[grid](xr, n_float, inv_scale, BLOCK=_BLOCK)
    else:
        xf.mul_(inv_scale)


def _views(xf):
    return xf.real, xf.imag


def _direct(x, batch, channels, seqlen):
    fft_size = 2 * seqlen
    freq_len = seqlen + 1
    xf = torch.empty((batch, channels, freq_len),
                     device=x.device, dtype=torch.complex64)
    torch.fft.rfft(x, n=fft_size, out=xf)
    _scale_inplace(xf, fft_size)
    return _views(xf)


def _build_graph(x, batch, channels, seqlen):
    fft_size = 2 * seqlen
    freq_len = seqlen + 1
    xf = torch.empty((batch, channels, freq_len),
                     device=x.device, dtype=torch.complex64)

    warmup_stream = torch.cuda.Stream()
    warmup_stream.wait_stream(torch.cuda.current_stream())
    with torch.cuda.stream(warmup_stream):
        for _ in range(3):
            torch.fft.rfft(x, n=fft_size, out=xf)
            _scale_inplace(xf, fft_size)
    torch.cuda.current_stream().wait_stream(warmup_stream)

    graph = torch.cuda.CUDAGraph()
    with torch.cuda.graph(graph):
        torch.fft.rfft(x, n=fft_size, out=xf)
        _scale_inplace(xf, fft_size)

    graph.replay()
    ref_r, ref_i = _torch_ref(x)
    out_r, out_i = _views(xf)
    if not (torch.allclose(out_r, ref_r, atol=1e-5, rtol=1e-5) and
            torch.allclose(out_i, ref_i, atol=1e-5, rtol=1e-5)):
        raise RuntimeError("cuda graph output mismatch")

    return x, graph, xf, out_r, out_i


@torch.no_grad()
def run(x: torch.Tensor):
    if not x.is_cuda:
        return _torch_ref(x)

    if x.dtype != torch.float32:
        x = x.to(torch.float32)

    _check_triton(x.device)

    batch, channels, seqlen = x.shape
    key = (x.device.index, batch, channels, seqlen, x.stride(), x.data_ptr())
    entry = _cache.get(key)

    if entry is None:
        try:
            entry = ("graph",) + _build_graph(x, batch, channels, seqlen)
        except Exception:
            entry = ("direct",)
        _cache[key] = entry

    if entry[0] == "graph":
        _, captured_x, graph, xf, out_r, out_i = entry
        if captured_x.data_ptr() == x.data_ptr():
            try:
                graph.replay()
                return out_r, out_i
            except Exception:
                _cache[key] = ("direct",)
        else:
            _cache.pop(key, None)

    return _direct(x, batch, channels, seqlen)
